mapper.update:
update mag_agent_session

    ragflow_session_id = #{ragflowSessionId},
    session_title = #{sessionTitle},
    status = #{status},
    last_message_time = #{lastMessageTime},
    update_by = #{updateBy},
    update_time = #{updateTime}

where session_id = #{sessionId}
  and user_id = #{userId}

mapper.select:

where user_id = #{userId}

  and agent_code = #{agentCode}

order by last_message_time desc, create_time desc

mapper.delete:
delete from mag_agent_session
where session_id = #{sessionId}
  and user_id = #{userId}
